import{_ as t,o as e,c as r,a2 as i}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F13: 資本支出效能與股利防禦 - 投資研究員 審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/4967_十銓/20260428/F13_資本支出效能與股利防禦_投資研究員.md","filePath":"審計報告庫/財務審計/4967_十銓/20260428/F13_資本支出效能與股利防禦_投資研究員.md"}'),l={name:"審計報告庫/財務審計/4967_十銓/20260428/F13_資本支出效能與股利防禦_投資研究員.md"};function o(n,a,s,h,c,d){return e(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="f13-資本支出效能與股利防禦-投資研究員-審計報告" tabindex="-1">F13: 資本支出效能與股利防禦 - 投資研究員 審計報告 <a class="header-anchor" href="#f13-資本支出效能與股利防禦-投資研究員-審計報告" aria-label="Permalink to &quot;F13: 資本支出效能與股利防禦 - 投資研究員 審計報告&quot;">​</a></h1><p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>資本支出 (CapEx) 的投入效能為何？自由現金流 (FCF) 是否足以支撐其股利政策？是否存在「借債配息」之虛耗現象？</p></blockquote><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><ul><li><strong>核心結論</strong>：CapEx佔營收僅0.51%（極低），2025年FCF為-36.26億，股利2.55億以舉債支撐，存在「借債配息」特徵，但本質為擴張期營運資金需求而非財務虛耗。</li><li><strong>風險評級</strong>：中</li><li><strong>數據時效</strong>：根據截至2025年12月最新年報數據</li></ul><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><ul><li><strong>重點數據</strong>：CapEx三年僅3.49億（佔營收0.07%），2025年營運現金流-35.21億、FCF-36.26億；股利從7,015萬增至2.55億；總負債64.42億→101.66億。</li><li><strong>診斷見解</strong>：CapEx極低（輕資產模式），但營運資金需求巨大吞噬現金。公司以舉債22.75億支撐營運與配息，股利政策與現金流脫節。</li></ul><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="capex效能實測" tabindex="-1">CapEx效能實測 <a class="header-anchor" href="#capex效能實測" aria-label="Permalink to &quot;CapEx效能實測&quot;">​</a></h3><ul><li><strong>核心重點</strong>：2024年CapEx 3,593萬→2025年營收+4.9億（倍數13.6倍）；2023年CapEx 881萬→2024年營收+33.7億（倍數382倍）。CapEx佔營收0.04%-0.51%。</li><li><strong>深度見解</strong>：CapEx效率極高，因商業模式不需大量固定資產。核心資本需求在營運資金（存貨+應收），非廠房設備。2025年新增兩條SMT產線反映在僅1.03億PPE購置中，規模極小，CapEx本身不構成風險。</li></ul><h3 id="fcf覆蓋測試" tabindex="-1">FCF覆蓋測試 <a class="header-anchor" href="#fcf覆蓋測試" aria-label="Permalink to &quot;FCF覆蓋測試&quot;">​</a></h3><ul><li><strong>核心重點</strong>：2024年FCF 8.90億/股利1.40億=6.4倍（安全）；2025年FCF -36.26億/股利2.55億=-14.2倍（嚴重不足）；2023年FCF -4.37億/股利0.70億=-6.2倍。</li><li><strong>深度見解</strong>：FCF波動劇烈根源在營運資金循環。2023與2025年FCF為負係因應收與存貨同步膨脹（合計+60億），反映業務擴張下的現金佔用。2024年FCF為正因前一年庫存消化後現金回流。關鍵在應收41.31億與存貨91.91億能否於2026年正常回收。</li></ul><h3 id="股利穩定性測試" tabindex="-1">股利穩定性測試 <a class="header-anchor" href="#股利穩定性測試" aria-label="Permalink to &quot;股利穩定性測試&quot;">​</a></h3><ul><li><strong>核心重點</strong>：2025年決議配發每股10元現金股利（約8.50億），較2024年3元暴增233%。配息率76.6%（相對EPS 13.06元）尚屬合理，但2025年底現金僅7.08億，需支付8.50億股利，缺口明確。</li><li><strong>深度見解</strong>：公司已發行第四次有擔保轉換公司債（2025年11月），資金來源為舉債。若景氣反轉，高配息政策不可持續。10元配息在營收下滑20%情境下（淨利約8.5億），配息率100%時剛好覆蓋，安全邊際極薄。</li></ul><h2 id="💡-專家評析-skepticism-mandate" tabindex="-1">💡 專家評析 (Skepticism Mandate) <a class="header-anchor" href="#💡-專家評析-skepticism-mandate" aria-label="Permalink to &quot;💡 專家評析 (Skepticism Mandate)&quot;">​</a></h2><ul><li><strong>空頭風險一</strong>：「借債配息」特徵明確——2025年現金股利2.55億全數來自舉債淨增22.75億。2026年10元配息（約8.50億）將進一步侵蝕現金儲備。若DRAM/NAND價格在2027年反轉，庫存91.91億面臨跌價損失，届時「以債養息」模式將遭遇信用收縮風險。流動負債100.81億對現金7.08億覆蓋倍數僅0.07倍，流動性壓力不容忽視。</li><li><strong>空頭風險二</strong>：股利政策與營運現金流嚴重脫節。2025年營運現金流-35.21億卻配發2.55億股利（相對營運CF配息率-7.2%）。管理層同時大幅調高配息（3元→10元），優先「迎合市場預期」多於「維護財務紀律」。若AI需求降溫，雙重壓力（庫存貶值+高配息承諾）將形成財務螺旋風險。</li></ul><h2 id="📚-證據來源-veracity-check" tabindex="-1">📚 證據來源 (Veracity Check) <a class="header-anchor" href="#📚-證據來源-veracity-check" aria-label="Permalink to &quot;📚 證據來源 (Veracity Check)&quot;">​</a></h2><ul><li><strong>FinMind</strong>: 失敗（API import error）</li><li><strong>yfinance</strong>: OK - CapEx: 2023: -8,813,000 / 2024: -35,926,000 / 2025: -104,817,000; FCF: 2023: -437,014,000 / 2024: 889,864,000 / 2025: -3,625,521,000; Div Paid: 2023: -70,149,000 / 2024: -140,297,000 / 2025: -254,890,000</li><li><strong>年報/法說</strong>: MOPS確認2025年11月發行國內第四次有擔保轉換公司債；2026年2月董事會決議10元配息</li><li><strong>關鍵核對碼</strong>: FCF 2025: -3,625,521,000 TWD; Total Debt 2025: 3,316,054,000 TWD; Cash 2025: 708,402,000 TWD; Dividend Paid 2025: 254,890,000 TWD</li></ul>',19)])])}const g=t(l,[["render",o]]);export{u as __pageData,g as default};
